protected override void OnModelCreating(ModelBuilder modelBuilder)
{
    // Cosmos DB indexing is managed via Azure Portal/Bicep, not EF Core.
    // HasIndex was removed — it throws in EF Core 9.

    modelBuilder.Entity<Product>(entity =>
    {
        entity.ToContainer("Products");

        // Preserve EF Core 8 discriminator property name so existing documents
        // (which store "Discriminator") remain compatible with both EF queries
        // and direct SQL queries that reference c.Discriminator.
        // EF Core 9 defaults to "$type" — do NOT use that with existing data.
        entity.HasDiscriminator<string>("Discriminator");

        // Preserve EF Core 8 compound id format ("Product|123") so that
        // FindAsync and point-reads continue to work against existing documents.
        // EF Core 9 defaults to key-only ids ("123").
        entity.HasRootDiscriminatorInJsonId(true);
    });
}

